teach_cooking_skills <- function(member_teaching_preferences) {
  n <- length(member_teaching_preferences)

  # Step 1: Find SCCs using Kosaraju's algorithm
  stack <- integer(0)
  visited <- logical(n)
  scc_id <- integer(n)
  scc_count <- 0

  # Helper function to perform DFS and find SCCs
  dfs <- function(v) {
    visited[v] <<- TRUE
    for (w in member_teaching_preferences[[v]]) {
      if (!visited[w]) {
        dfs(w)
      }
    }
    stack <<- c(v, stack)
  }

  # First pass to fill the stack
  for (v in 1:n) {
    if (!visited[v]) {
      dfs(v)
    }
  }

  # Step 2: Transpose the graph
  transpose <- lapply(1:n, function(x) integer(0))
  for (v in 1:n) {
    for (w in member_teaching_preferences[[v]]) {
      transpose[[w]] <- c(v, transpose[[w]])
    }
  }

  # Helper function to perform DFS and find SCCs in the transposed graph
  dfs_transpose <- function(v) {
    visited[v] <<- FALSE
    scc_id[v] <<- scc_count
    for (w in transpose[[v]]) {
      if (visited[w]) {
        dfs_transpose(w)
      }
    }
  }

  # Second pass to find SCCs
  while (length(stack) > 0) {
    v <- stack[1]
    stack <- stack[-1]
    if (visited[v]) {
      scc_count <- scc_count + 1
      dfs_transpose(v)
    }
  }

  # Step 3: Condense the graph into a DAG
  dag <- lapply(1:scc_count, function(x) integer(0))
  for (v in 1:n) {
    for (w in member_teaching_preferences[[v]]) {
      if (scc_id[v] != scc_id[w]) {
        dag[[scc_id[v]]] <- c(scc_id[w], dag[[scc_id[v]]])
      }
    }
  }

  # Step 4: Find sources in the DAG
  in_degree <- rep(0, scc_count)
  for (i in 1:scc_count) {
    for (j in dag[[i]]) {
      in_degree[j] <- in_degree[j] + 1
    }
  }

  # Step 5: Count the sources
  sources <- sum(in_degree == 0)

  return(sources)
}

